-  // select(mask, mload(,,mask,0), 0) -> mload(,,mask,0)
-  // Load inst is intentionally not checked for hasOneUse()
-  if (match(FalseVal, m_Zero()) &&
-      (match(TrueVal, m_MaskedLoad(m_Value(), m_Value(), m_Specific(CondVal),
